#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long k = N/2;
        long long ans = (N % 2 == 0) ? k*(k+1) : (k+1)*(k+1);
        printf("%lld\n", ans);
    }
    return 0;
}

